from odoo import fields, models, api, _
from odoo.http import request
import logging

_logger = logging.getLogger(__name__)

class ir_ui_menu(models.Model):
    _inherit = 'ir.ui.menu'

    @api.model
    def search(self, args, offset=0, limit=None, order=None):
        ids = super(ir_ui_menu, self).search(args, offset=0, limit=None, order=order)
        user = self.env.user
        try:
            cids = request.httprequest.cookies.get('cids') and request.httprequest.cookies.get('cids').split(',')[0] or self.env.company.id
            cids = int(cids)
        except Exception:
            cids = self.env.company.id

        access_management_obj = self.env['access.management'].sudo()
        access_management_rules = access_management_obj.search([
            ('user_ids', 'in', user.id),
            ('company_ids', 'in', cids),
            ('active', '=', True)
        ])
        hide_menus = access_management_rules.mapped('hide_menu_ids.menu_id')
        _logger.info("Access Management Search Debug - user: %s (ID %s), cids: %s, rules found: %s, hide_menus: %s",
                     user.name, user.id, cids, access_management_rules.mapped('name'), hide_menus)

        for menu_id in hide_menus:
            menu_id = self.browse(menu_id)
            if menu_id in ids:
                ids = ids - menu_id
        if offset:
            ids = ids[offset:]
        if limit:
            ids = ids[:limit]
        return ids

    @api.model
    def load_menus(self, debug=False):
        res = super(ir_ui_menu, self).load_menus(debug)
        if not res or not isinstance(res, dict) or 'menus' not in res:
            return res

        user = self.env.user
        try:
            cids = request.httprequest.cookies.get('cids') and request.httprequest.cookies.get('cids').split(',')[0] or self.env.company.id
            cids = int(cids)
        except Exception:
            cids = self.env.company.id

        access_management_obj = self.env['access.management'].sudo()
        access_management_rules = access_management_obj.search([
            ('user_ids', 'in', user.id),
            ('company_ids', 'in', cids),
            ('active', '=', True)
        ])
        hide_menu_ids = access_management_rules.mapped('hide_menu_ids.menu_id')

        _logger.info("Access Management Load Menus Debug - user: %s (ID %s), cids: %s, rules found: %s, hide_menus: %s",
                     user.name, user.id, cids, access_management_rules.mapped('name'), hide_menu_ids)

        if not hide_menu_ids:
            return res

        # Convert hide_menu_ids to set of both int and str to handle any key representation safely
        to_hide = set()
        for m in hide_menu_ids:
            to_hide.add(m)
            to_hide.add(str(m))

        # Copy the dictionaries to avoid mutating Odoo's cached menu tree
        res = dict(res)
        res['menus'] = {menu_id: dict(menu) for menu_id, menu in res['menus'].items()}
        if 'root_menu_ids' in res:
            res['root_menu_ids'] = list(res['root_menu_ids'])

        # Find all descendants of hidden menus recursively
        added = True
        while added:
            added = False
            for menu_id, menu in res['menus'].items():
                if menu_id not in to_hide:
                    parent_id = menu.get('parent_id')
                    p_id = parent_id[0] if isinstance(parent_id, tuple) else parent_id
                    if p_id in to_hide or str(p_id) in to_hide:
                        to_hide.add(menu_id)
                        to_hide.add(str(menu_id))
                        added = True

        # Remove hidden menus from the tree
        res['menus'] = {
            menu_id: menu
            for menu_id, menu in res['menus'].items()
            if menu_id not in to_hide
        }

        if 'root_menu_ids' in res:
            res['root_menu_ids'] = [r for r in res['root_menu_ids'] if r not in to_hide]

        # Filter the children lists in the remaining menus
        for menu in res['menus'].values():
            if 'children' in menu:
                menu['children'] = [c for c in menu['children'] if c not in to_hide]
            if 'child_id' in menu:
                menu['child_id'] = [c for c in menu['child_id'] if c not in to_hide]

        return res

    @api.model_create_multi
    def create(self, vals_list):
        res = super(ir_ui_menu, self).create(vals_list)
        menu_item_obj = self.env['menu.item']
        for record in res:
            menu_item_obj.create({'name':record.display_name,'menu_id':record.id})
        return res

    def unlink(self):
        menu_item_obj = self.env['menu.item']
        for record in self:
            menu_item_obj.search([('menu_id','=',record.id)]).unlink()
        return super(ir_ui_menu, self).unlink()

from odoo import fields, models, api, _
from odoo.http import request
import logging

_logger = logging.getLogger(__name__)

class ir_ui_menu(models.Model):
    _inherit = 'ir.ui.menu'

    @api.model
    def search(self, args, offset=0, limit=None, order=None):
        ids = super(ir_ui_menu, self).search(args, offset=0, limit=None, order=order)
        user = self.env.user
        try:
            cids = request.httprequest.cookies.get('cids') and request.httprequest.cookies.get('cids').split(',')[0] or self.env.company.id
            cids = int(cids)
        except Exception:
            cids = self.env.company.id
        
        access_management_obj = self.env['access.management'].sudo()
        access_management_rules = access_management_obj.search([
            ('user_ids', 'in', user.id),
            ('company_ids', 'in', cids),
            ('active', '=', True)
        ])
        hide_menus = access_management_rules.mapped('hide_menu_ids.menu_id')
        _logger.info("Access Management Search Debug - user: %s (ID %s), cids: %s, rules found: %s, hide_menus: %s",
                     user.name, user.id, cids, access_management_rules.mapped('name'), hide_menus)

        for menu_id in hide_menus:
            menu_id = self.browse(menu_id)
            if menu_id in ids:
                ids = ids - menu_id
        if offset:
            ids = ids[offset:]
        if limit:
            ids = ids[:limit]
        return ids

    @api.model
    def load_menus(self, debug=False):
        res = super(ir_ui_menu, self).load_menus(debug)
        # Be defensive: normalize different possible return shapes from Odoo core
        if not res or not isinstance(res, dict) or 'menus' not in res:
            return res

        user = self.env.user
        try:
            cids = request.httprequest.cookies.get('cids') and request.httprequest.cookies.get('cids').split(',')[0] or self.env.company.id
            cids = int(cids)
        except Exception:
            cids = self.env.company.id

        access_management_obj = self.env['access.management'].sudo()
        access_management_rules = access_management_obj.search([
            ('user_ids', 'in', user.id),
            ('company_ids', 'in', cids),
            ('active', '=', True)
        ])
        hide_menu_ids = access_management_rules.mapped('hide_menu_ids.menu_id')

        _logger.info("Access Management Load Menus Debug - user: %s (ID %s), cids: %s, rules found: %s, hide_menus: %s",
                     user.name, user.id, cids, access_management_rules.mapped('name'), hide_menu_ids)

        if not hide_menu_ids:
            return res

        # Normalize res['menus'] into a dict keyed by integer id so the algorithm
        # can work regardless of the exact shape returned by different Odoo versions.
        original_menus = res['menus']
        menus_was_list = False
        # Build a menu dict keyed by int id -> menu dict
        menus_by_id = {}

        if isinstance(original_menus, dict):
            for key, menu in original_menus.items():
                try:
                    mid = int(key)
                except Exception:
                    # fallback: try to extract id from menu itself
                    mid = int(menu.get('id')) if menu.get('id') else None
                if mid is None:
                    continue
                menus_by_id[mid] = dict(menu)
        elif isinstance(original_menus, (list, tuple)):
            menus_was_list = True
            for menu in original_menus:
                mid = None
                if isinstance(menu, dict) and menu.get('id'):
                    try:
                        mid = int(menu.get('id'))
                    except Exception:
                        mid = None
                if mid is None:
                    # ignore malformed entries
                    continue
                menus_by_id[mid] = dict(menu)
        else:
            # Unknown shape, give up safely
            return res

        # Helper to extract parent id as int or None
        def _parent_id_as_int(parent_val):
            if parent_val is None:
                return None
            if isinstance(parent_val, (list, tuple)) and parent_val:
                try:
                    return int(parent_val[0])
                except Exception:
                    return None
            try:
                return int(parent_val)
            except Exception:
                return None

        # Helper to normalize children list to ints
        def _children_as_ints(children_val):
            if not children_val:
                return []
            out = []
            for c in children_val:
                if isinstance(c, (list, tuple)) and c:
                    try:
                        out.append(int(c[0]))
                    except Exception:
                        continue
                else:
                    try:
                        out.append(int(c))
                    except Exception:
                        continue
            return out

        # Build initial to_hide set
        to_hide = set()
        for m in hide_menu_ids:
            try:
                mid = int(m)
            except Exception:
                continue
            to_hide.add(mid)

        # Recursively add descendants
        added = True
        while added:
            added = False
            for mid, menu in list(menus_by_id.items()):
                if mid in to_hide:
                    continue
                parent_raw = menu.get('parent_id')
                p_id = _parent_id_as_int(parent_raw)
                if p_id and p_id in to_hide:
                    to_hide.add(mid)
                    added = True

        # Remove hidden menus
        for hid in list(to_hide):
            if hid in menus_by_id:
                menus_by_id.pop(hid, None)

        # Filter children and child_id fields
        for menu in menus_by_id.values():
            if 'children' in menu:
                menu['children'] = [c for c in _children_as_ints(menu.get('children')) if c not in to_hide]
            if 'child_id' in menu:
                menu['child_id'] = [c for c in _children_as_ints(menu.get('child_id')) if c not in to_hide]

        # Filter root_menu_ids
        if 'root_menu_ids' in res:
            try:
                res['root_menu_ids'] = [int(r) for r in res.get('root_menu_ids') if int(r) not in to_hide]
            except Exception:
                # keep original if unexpected shape
                pass

        # Rebuild res['menus'] preserving original shape
        if menus_was_list:
            res['menus'] = [menu for menu in [dict(m) for m in menus_by_id.values()]]
        else:
            # key as int => some callers expect string keys; keep int keys
            res['menus'] = {mid: menu for mid, menu in menus_by_id.items()}

        return res
    
    @api.model_create_multi
    def create(self, vals_list):
        res = super(ir_ui_menu, self).create(vals_list)
        menu_item_obj = self.env['menu.item']
        for record in res:
            menu_item_obj.create({'name':record.display_name,'menu_id':record.id})
        return res

    def unlink(self):
        menu_item_obj = self.env['menu.item']
        for record in self:
            menu_item_obj.search([('menu_id','=',record.id)]).unlink()
        return super(ir_ui_menu, self).unlink()

from odoo import fields, models, api, SUPERUSER_ID,_
from odoo.exceptions import UserError, AccessDenied
import logging
_logger = logging.getLogger(__name__)

class res_users(models.Model):
    _inherit = 'res.users'

    access_management_ids = fields.Many2many('access.management', 'access_management_users_rel_ah', 'user_id', 'access_management_id', 'Access Pack')

    # allow_ip_ids = fields.One2many('allow.ip', 'user_id', 'Allow IP')

    def write(self, vals):
        res = super(res_users, self).write(vals)
        for access in self.access_management_ids:
            if self.env.company in access.company_ids and access.readonly:
                if self.has_group('base.group_system') or self.has_group('base.group_erp_manager'):
                    raise UserError(_('Admin user can not be set as a read-only..!'))
        return res

    @api.model_create_multi
    def create(self, vals_list):
        res = super(res_users, self).create(vals_list)
        for record in self:
            for access in record.access_management_ids:    
                if self.env.company in access.company_ids and access.readonly:
                    if record.has_group('base.group_system') or record.has_group('base.group_erp_manager'):
                        raise UserError(_('Admin user can not be set as a read-only..!'))
        return res


    # NOTE: Odoo 19 changed _login signature from (cls, db, login, password, user_agent_env)
    #       to (cls, credential, user_agent_env=None) where credential is a dict.
    #       Old implementation caused TypeError when auth_passkey called super()._login().
    @classmethod
    def _login(cls, credential, user_agent_env=None):
        res = super(res_users, cls)._login(credential, user_agent_env=user_agent_env)
        try:
            db = user_agent_env.get('db') if user_agent_env else None
            login = credential.get('login') if isinstance(credential, dict) else credential
            with cls.pool.cursor() as cr:
                self = api.Environment(cr, SUPERUSER_ID, {})[cls._name]
                access_management_obj = self.env['access.management']
                if access_management_obj.search([('user_ids', 'in', res), ('disable_login', '=', True)]).id:
                    raise AccessDenied()
        except AccessDenied:
            _logger.info("Login failed for db:%s login:%s", db, login)
            raise
        return res

from odoo import fields, models, api, SUPERUSER_ID,_
from odoo.exceptions import UserError, AccessDenied
import logging
_logger = logging.getLogger(__name__)

class res_users(models.Model):
    _inherit = 'res.users'

    access_management_ids = fields.Many2many('access.management', 'access_management_users_rel_ah', 'user_id', 'access_management_id', 'Access Pack')

    # allow_ip_ids = fields.One2many('allow.ip', 'user_id', 'Allow IP')
    
    def write(self, vals):
        res = super(res_users, self).write(vals)
        for access in self.access_management_ids:
            if self.env.company in access.company_ids and access.readonly:
                if self.has_group('base.group_system') or self.has_group('base.group_erp_manager'):
                    raise UserError(_('Admin user can not be set as a read-only..!'))
        return res

    @api.model_create_multi
    def create(self, vals_list):
        res = super(res_users, self).create(vals_list)
        # iterate over created records (res), not over self
        for record in res:
            for access in record.access_management_ids:
                if self.env.company in access.company_ids and access.readonly:
                    if record.has_group('base.group_system') or record.has_group('base.group_erp_manager'):
                        raise UserError(_('Admin user can not be set as a read-only..!'))
        return res


    # NOTE: Odoo 19 changed _login signature from (cls, db, login, password, user_agent_env)
    #       to (cls, credential, user_agent_env=None) where credential is a dict.
    #       Old implementation caused TypeError when auth_passkey called super()._login().
    @classmethod
    def _login(cls, credential, user_agent_env=None):
        res = super(res_users, cls)._login(credential, user_agent_env=user_agent_env)
        try:
            db = user_agent_env.get('db') if user_agent_env else None
            login = credential.get('login') if isinstance(credential, dict) else credential
            with cls.pool.cursor() as cr:
                self = api.Environment(cr, SUPERUSER_ID, {})[cls._name]
                access_management_obj = self.env['access.management']
                if access_management_obj.search([('user_ids', 'in', res), ('disable_login', '=', True)]).id:
                    raise AccessDenied()
        except AccessDenied:
            _logger.info("Login failed for db:%s login:%s", db, login)
            raise
        return res

"""Standalone tests for the menu-hide normalization algorithm.

This file does not import Odoo. It mirrors the normalization + hide logic
implemented in `models/ir_ui_menu.py` so we can test behavior on various
`load_menus()` shapes.
"""
from pprint import pprint


def apply_hide_to_res(res, hide_menu_ids):
    original_menus = res['menus']
    menus_was_list = False
    menus_by_id = {}

    if isinstance(original_menus, dict):
        for key, menu in original_menus.items():
            try:
                mid = int(key)
            except Exception:
                mid = int(menu.get('id')) if menu.get('id') else None
            if mid is None:
                continue
            menus_by_id[mid] = dict(menu)
    elif isinstance(original_menus, (list, tuple)):
        menus_was_list = True
        for menu in original_menus:
            mid = None
            if isinstance(menu, dict) and menu.get('id'):
                try:
                    mid = int(menu.get('id'))
                except Exception:
                    mid = None
            if mid is None:
                continue
            menus_by_id[mid] = dict(menu)
    else:
        return res

    def _parent_id_as_int(parent_val):
        if parent_val is None:
            return None
        if isinstance(parent_val, (list, tuple)) and parent_val:
            try:
                return int(parent_val[0])
            except Exception:
                return None
        try:
            return int(parent_val)
        except Exception:
            return None

    def _children_as_ints(children_val):
        if not children_val:
            return []
        out = []
        for c in children_val:
            if isinstance(c, (list, tuple)) and c:
                try:
                    out.append(int(c[0]))
                except Exception:
                    continue
            else:
                try:
                    out.append(int(c))
                except Exception:
                    continue
        return out

    to_hide = set()
    for m in hide_menu_ids:
        try:
            to_hide.add(int(m))
        except Exception:
            pass

    added = True
    while added:
        added = False
        for mid, menu in list(menus_by_id.items()):
            if mid in to_hide:
                continue
            p_id = _parent_id_as_int(menu.get('parent_id'))
            if p_id and p_id in to_hide:
                to_hide.add(mid)
                added = True

    for hid in list(to_hide):
        menus_by_id.pop(hid, None)

    for menu in menus_by_id.values():
        if 'children' in menu:
            menu['children'] = [c for c in _children_as_ints(menu.get('children')) if c not in to_hide]
        if 'child_id' in menu:
            menu['child_id'] = [c for c in _children_as_ints(menu.get('child_id')) if c not in to_hide]

    if menus_was_list:
        res['menus'] = [menu for menu in menus_by_id.values()]
    else:
        res['menus'] = {mid: menu for mid, menu in menus_by_id.items()}

    if 'root_menu_ids' in res:
        try:
            res['root_menu_ids'] = [int(r) for r in res.get('root_menu_ids') if int(r) not in to_hide]
        except Exception:
            pass

    return res


def test_case_dict_keys():
    res = {
        'menus': {
            1: {'id': 1, 'name': 'Dash', 'parent_id': None, 'children': [2, 3]},
            2: {'id': 2, 'name': 'Sales', 'parent_id': (1, 'Dash'), 'children': [4]},
            3: {'id': 3, 'name': 'Accounting', 'parent_id': (1, 'Dash'), 'children': []},
            4: {'id': 4, 'name': 'Orders', 'parent_id': (2, 'Sales'), 'children': []},
        },
        'root_menu_ids': [1]
    }
    out = apply_hide_to_res(res.copy(), [2])
    print('\nTest dict_keys hide [2]:')
    pprint(out)


def test_case_list_of_dicts():
    res = {
        'menus': [
            {'id': 1, 'name': 'Dash', 'parent_id': None, 'children': [2, 3]},
            {'id': 2, 'name': 'Sales', 'parent_id': 1, 'children': [4]},
            {'id': 3, 'name': 'Accounting', 'parent_id': 1, 'children': []},
            {'id': 4, 'name': 'Orders', 'parent_id': 2, 'children': []},
        ],
        'root_menu_ids': [1]
    }
    out = apply_hide_to_res(res.copy(), ["2"])  # string id
    print('\nTest list_of_dicts hide ["2"]:')
    pprint(out)


def test_case_string_keys():
    res = {
        'menus': {
            '1': {'id': '1', 'name': 'Dash', 'parent_id': None, 'children': ['2']},
            '2': {'id': '2', 'name': 'Sales', 'parent_id': ('1', 'Dash'), 'children': []},
        },
        'root_menu_ids': ['1']
    }
    out = apply_hide_to_res(res.copy(), [2])
    print('\nTest string_keys hide [2]:')
    pprint(out)


if __name__ == '__main__':
    test_case_dict_keys()
    test_case_list_of_dicts()
    test_case_string_keys()
